sql:
SELECT name
FROM games
WHERE is_multiplayer = 0 AND metacritic_score = (SELECT MAX(metacritic_score) FROM games WHERE is_multiplayer = 0);

SELECT name
FROM games
WHERE developer = 'Capcom' AND metacritic_score > (SELECT AVG(metacritic_score) FROM games);

SELECT games.name, genres.genre_name
FROM games
INNER JOIN genres ON games.genre_id = genres.genre_id;

external_knowledge:
- 'dimensions of various genres and platforms' refers to the different categories games can belong to and the platforms where these games are available;
- 'titles of games' refers to `games.name`;
- 'names of the worlds they inhabit' refers to `genres.genre_name`;
- 'the lands they call home' refers to `platforms.platform_name`.

sql:
SELECT games.name, games.developer
FROM games
WHERE games.game_id IN (
    SELECT user_reviews.game_id
    FROM user_reviews
);

external_knowledge:
- "emerging like new stars" refers to newly released games;
- "galactic map of the gaming cosmos" is a metaphor for the space of all available games;
- "year's final countdown in 2020" means after December 31, 2020;
- "garnered the admiration of critics" is a figurative way of saying the games have earned high ratings from users;
- "shining brightly with ratings of at least 80" means user ratings are 80 or higher.

sql:
SELECT AVG(critic_rating_value) 
FROM critic_reviews 
WHERE game_id = 1;

SELECT name
FROM games
WHERE genre_id NOT IN (
  SELECT genre_id
  FROM genres
);
